def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Handle special cases for better natural language generation
    # Group related facts and restructure for better flow
    sentences = []

    # Extract country information to handle language and leader relationships properly
    country_info = {}
    location_info = {}

    for subject, triples in subject_map.items():
        base = subject
        details = []

        for predicate, obj in triples:
            if predicate == "cityServed":
                details.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                details.append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                details.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                details.append(f"is operated by {obj}")
            elif predicate == "location":
                details.append(f"is located in {obj}")
                location_info[subject] = obj
            elif predicate == "elevationAboveTheSeaLevel":
                details.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                details.append(f"The runway length of {subject} is {obj} metres")
            elif predicate == "country":
                details.append(f"is located in {obj}")
                country_info[subject] = obj
            elif predicate == "capital":
                details.append(f"has a capital of {obj}")
            elif predicate == "language":
                # Countries don't "speak" languages, people do
                if subject in country_info.values() or subject in country_info:
                    details.append(f"{obj} is spoken in {subject}")
                else:
                    details.append(f"has {obj} as a language")
            elif predicate == "leader":
                # Better phrasing for leaders
                details.append(f"has {obj} as its leader")
            elif predicate == "owner":
                details.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                details.append(f"The first runway length of {subject} is {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                details.append(f"The first runway surface type of {subject} is {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                details.append(f"The third runway length of {subject} is {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                details.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                details.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                details.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                details.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                details.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                details.append(f"has a leader party of {obj}")
            elif predicate == "runwaySurfaceType":
                details.append(f"The runway surface type of {subject} is {obj}")
            else:
                # For numeric attributes, use more natural phrasing
                if "Length" in predicate or "LengthFeet" in predicate or "LengthMetre" in predicate:
                    display_name = predicate.replace('1stRunwayLengthFeet', 'first runway length') \
                                           .replace('3rdRunwayLengthFeet', 'third runway length') \
                                           .replace('Length', 'length') \
                                           .replace('LengthFeet', 'length in feet') \
                                           .replace('LengthMetre', 'length in metres')
                    details.append(f"The {display_name} of {subject} is {obj}")
                else:
                    details.append(f"has a {predicate} of {obj}")

        if details:
            base += " " + ", ".join(details)
        sentences.append(base)

    # Reorganize sentences for better flow, especially for location chains
    # For example: Tirstrup is in Denmark, and Denmark has leader Margrethe II
    if len(sentences) > 1:
        # Try to create a more natural chain for location relationships
        # Look for location and country relationships
        final_sentences = []
        used = set()

        for sentence in sentences:
            if not sentence.strip():
                continue
            if "is located in" in sentence:
                parts = sentence.split("is located in")
                if len(parts) == 2:
                    location = parts[0].strip()
                    country = parts[1].strip().rstrip(" ,.")
                    # Look for country's attributes
                    for other_sentence in sentences:
                        if other_sentence.startswith(country) and other_sentence not in used:
                            if "has" in other_sentence or "is spoken" in other_sentence:
                                country_detail = other_sentence.replace(country, "").strip().lstrip(" ,")
                                # Merge into location sentence
                                sentence = sentence.replace(f"is located in {country}", f"is located in {country}, which {country_detail[3:]}")
                                used.add(other_sentence)
                                break
            final_sentences.append(sentence)

        # Add any unused country sentences
        for sentence in sentences:
            if sentence not in used and sentence.strip():
                if sentence not in final_sentences:
                    final_sentences.append(sentence)

        sentences = [s for s in final_sentences if s.strip()]

    return " ".join(sentences).rstrip() + "."

